import{_ as o,o as a,c as e,ai as r}from"./chunks/framework.BH_J6TYN.js";const h=JSON.parse('{"title":"SYNTIweb — Product Context para Generación de Documentación","description":"","frontmatter":{},"headers":[],"relativePath":"context.md","filePath":"context.md"}'),d={name:"context.md"};function i(n,t,s,l,c,u){return a(),e("div",null,[...t[0]||(t[0]=[r('<h1 id="syntiweb-—-product-context-para-generacion-de-documentacion" tabindex="-1">SYNTIweb — Product Context para Generación de Documentación <a class="header-anchor" href="#syntiweb-—-product-context-para-generacion-de-documentacion" aria-label="Permalink to &quot;SYNTIweb — Product Context para Generación de Documentación&quot;">​</a></h1><blockquote><p>Este archivo es la fuente de verdad para Claude al generar documentación. NO publicar en Mintlify. Solo uso interno de agentes.</p></blockquote><hr><h2 id="producto" tabindex="-1">PRODUCTO <a class="header-anchor" href="#producto" aria-label="Permalink to &quot;PRODUCTO&quot;">​</a></h2><p><strong>Nombre:</strong> SYNTIweb<br><strong>Tipo:</strong> SaaS multitenant — landing pages para negocios venezolanos<br><strong>URL producción:</strong> syntiweb.com<br><strong>Stack:</strong> Laravel 12 · Tailwind v4 · Preline 4.1.2 · Alpine.js · MySQL · Hostinger<br><strong>Mercado:</strong> Venezuela 2026 — dolarizado informal, WhatsApp como canal principal</p><hr><h2 id="los-3-productos-blueprints" tabindex="-1">LOS 3 PRODUCTOS (blueprints) <a class="header-anchor" href="#los-3-productos-blueprints" aria-label="Permalink to &quot;LOS 3 PRODUCTOS (blueprints)&quot;">​</a></h2><h3 id="syntistudio" tabindex="-1">SYNTIstudio <a class="header-anchor" href="#syntistudio" aria-label="Permalink to &quot;SYNTIstudio&quot;">​</a></h3><p>Página web profesional completa para cualquier negocio.</p><p><strong>Para quién:</strong> Cualquier negocio local (barbería, clínica, academia, consultora, etc.)</p><p><strong>Features por plan:</strong></p><table tabindex="0"><thead><tr><th>Feature</th><th>Oportunidad $13/mes</th><th>Crecimiento $19/mes</th><th>Visión $25/mes</th></tr></thead><tbody><tr><td>Productos</td><td>20</td><td>50</td><td>Ilimitado</td></tr><tr><td>Servicios</td><td>3</td><td>6</td><td>9</td></tr><tr><td>Paletas de color</td><td>10</td><td>17</td><td>17 + custom</td></tr><tr><td>Secciones</td><td>hero, productos, servicios, contacto, pagos, cta, footer</td><td>+ about, testimonios</td><td>+ faq, sucursales</td></tr><tr><td>Fotos por producto</td><td>1</td><td>1</td><td>3 (slider)</td></tr></tbody></table><p><strong>Flows clave:</strong></p><ol><li>Registro → Wizard 5 pasos → landing publicada</li><li>Dashboard (Alt+S / long press logo) → PIN → editar todo</li><li>QR sticker descargable → imprimir → cliente escanea → ve la página</li></ol><hr><h3 id="syntifood" tabindex="-1">SYNTIfood <a class="header-anchor" href="#syntifood" aria-label="Permalink to &quot;SYNTIfood&quot;">​</a></h3><p>Menú digital para restaurantes con pedido directo por WhatsApp.</p><p><strong>Para quién:</strong> Restaurantes, fondas, comidas rápidas, reposterías</p><p><strong>Estructura del menú:</strong> Categoría con foto + lista de ítems con precio</p><p><strong>Features por plan:</strong></p><table tabindex="0"><thead><tr><th>Feature</th><th>Básico $9/mes</th><th>Semestral $39</th><th>Anual $69</th></tr></thead><tbody><tr><td>Fotos por categoría</td><td>6</td><td>12</td><td>18</td></tr><tr><td>Ítems en lista</td><td>50</td><td>100</td><td>150</td></tr><tr><td>Tasa BCV automática</td><td>✗</td><td>✅</td><td>✅</td></tr><tr><td>Extras/opciones</td><td>✗</td><td>✅</td><td>✅</td></tr><tr><td>Pedido Rápido → WhatsApp</td><td>✗</td><td>✗</td><td>✅</td></tr><tr><td>2 WhatsApp (ventas+soporte)</td><td>✗</td><td>✗</td><td>✅</td></tr></tbody></table><p><strong>Flow clave Pedido Rápido:</strong> Cliente acumula ítems → toca &quot;Enviar pedido&quot; → app construye mensaje formateado → abre WhatsApp listo para enviar</p><hr><h3 id="synticat" tabindex="-1">SYNTIcat <a class="header-anchor" href="#synticat" aria-label="Permalink to &quot;SYNTIcat&quot;">​</a></h3><p>Catálogo de productos con carrito y checkout por WhatsApp.</p><p><strong>Para quién:</strong> Tiendas, boutiques, distribuidoras, emprendedores con catálogo</p><p><strong>Features por plan:</strong></p><table tabindex="0"><thead><tr><th>Feature</th><th>Básico $9/mes</th><th>Semestral $39</th><th>Anual $69</th></tr></thead><tbody><tr><td>Productos</td><td>20</td><td>100</td><td>Ilimitado</td></tr><tr><td>Carrito completo</td><td>✗</td><td>✅</td><td>✅</td></tr><tr><td>Mini Order SC-XXXX</td><td>✗</td><td>✅</td><td>✅</td></tr><tr><td>Badges (nuevo/hot/promo)</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td>Variantes (talla/color)</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td>Variantes extras/opciones</td><td>✗</td><td>✗</td><td>✅</td></tr></tbody></table><p><strong>Flow clave carrito:</strong> Cliente navega catálogo → agrega productos → cart drawer lateral → genera código SC-XXXX → mensaje WhatsApp con orden completa</p><hr><h2 id="sistema-de-moneda" tabindex="-1">SISTEMA DE MONEDA <a class="header-anchor" href="#sistema-de-moneda" aria-label="Permalink to &quot;SISTEMA DE MONEDA&quot;">​</a></h2><ul><li>Símbolo: <strong>REF</strong> (no $ — mercado venezolano dolarizado informal)</li><li>Modos disponibles: <ul><li><code>reference_only</code> → solo muestra precio en REF</li><li><code>bolivares_only</code> → solo bolívares (convierte con tasa BCV)</li><li><code>both_toggle</code> → toggle automático REF/Bs</li><li><code>hidden</code> → sin precios visibles</li></ul></li><li>Tasa BCV se actualiza automáticamente vía API</li></ul><hr><h2 id="dashboard-panel-de-administracion" tabindex="-1">DASHBOARD (panel de administración) <a class="header-anchor" href="#dashboard-panel-de-administracion" aria-label="Permalink to &quot;DASHBOARD (panel de administración)&quot;">​</a></h2><ul><li><strong>Acceso:</strong> Alt+S en desktop / long press 3 seg en logo desde móvil</li><li><strong>Autenticación:</strong> PIN numérico (lo define el dueño)</li><li><strong>Tabs:</strong> Info · Productos · Servicios · Diseño · Analytics · Config</li><li><strong>Desde el celular:</strong> el dueño gestiona TODO sin computadora</li></ul><hr><h2 id="multitenancy" tabindex="-1">MULTITENANCY <a class="header-anchor" href="#multitenancy" aria-label="Permalink to &quot;MULTITENANCY&quot;">​</a></h2><ul><li>Cada negocio = un subdominio: <code>minegocio.syntiweb.com</code></li><li>Plan Anual (Studio/Cat): puede conectar dominio propio <code>www.minegocio.com</code></li><li>URL del QR siempre apunta al subdominio del tenant</li></ul><hr><h2 id="reglas-de-escritura-para-docs" tabindex="-1">REGLAS DE ESCRITURA PARA DOCS <a class="header-anchor" href="#reglas-de-escritura-para-docs" aria-label="Permalink to &quot;REGLAS DE ESCRITURA PARA DOCS&quot;">​</a></h2><ul><li><strong>Lector:</strong> dueño de negocio venezolano, NO desarrollador</li><li><strong>Tono:</strong> amigable, directo, como si le explicaras a un conocido</li><li><strong>Formato:</strong> pasos numerados, acciones concretas</li><li><strong>Largo:</strong> máximo 400 palabras por archivo</li><li><strong>Ejemplos:</strong> siempre usar negocios venezolanos reales (pizzería, barbería, tienda de ropa, fonda)</li><li><strong>Moneda:</strong> escribir REF, no $</li><li><strong>Sin jerga técnica:</strong> no decir &quot;tenant&quot;, &quot;blueprint&quot;, &quot;slug&quot;, &quot;endpoint&quot;</li><li><strong>Callouts Mintlify a usar:</strong><ul><li><code>&lt;Note&gt;</code> → información útil extra</li><li><code>&lt;Warning&gt;</code> → acción que puede causar pérdida de datos</li><li><code>&lt;Tip&gt;</code> → consejo para sacarle más provecho</li></ul></li></ul><hr><h2 id="demos-del-sistema-tenants-de-prueba" tabindex="-1">DEMOS DEL SISTEMA (tenants de prueba) <a class="header-anchor" href="#demos-del-sistema-tenants-de-prueba" aria-label="Permalink to &quot;DEMOS DEL SISTEMA (tenants de prueba)&quot;">​</a></h2><ul><li><strong>techstart</strong> → Plan Visión (Studio) — PIN: 1234</li><li><strong>pizzería</strong> → Plan Crecimiento (Studio)</li><li><strong>barbería</strong> → Plan Oportunidad (Studio)</li></ul><hr><h2 id="lo-que-no-existe-aun-no-documentar-todavia" tabindex="-1">LO QUE NO EXISTE AÚN (no documentar todavía) <a class="header-anchor" href="#lo-que-no-existe-aun-no-documentar-todavia" aria-label="Permalink to &quot;LO QUE NO EXISTE AÚN (no documentar todavía)&quot;">​</a></h2><ul><li>Pasarela de pago (Binance/transferencia) → Fase F</li><li>App móvil PWA → Fase F</li><li>Bot de soporte por tenant → Fase F</li><li>Dominio propio para Food → Fase F</li><li>API pública → Fase F</li></ul>',47)])])}const g=o(d,[["render",i]]);export{h as __pageData,g as default};
